use App\Models\User;
use Illuminate\Foundation\Testing\RefreshDatabase;
use Tests\TestCase;

class TenantIsolationTest extends TestCase
{
    use RefreshDatabase;

    public function test_users_only_see_tickets_in_their_organization(): void
    {
        $orgA = Organization::factory()-&gt;create();
        $orgB = Organization::factory()-&gt;create();

        $userA = User::factory()-&gt;create(['organization_id' =&gt; $orgA-&gt;id]);
        $userB = User::factory()-&gt;create(['organization_id' =&gt; $orgB-&gt;id]);

        Ticket::factory()-&gt;create([
            'organization_id' =&gt; $orgA-&gt;id,
            'user_id' =&gt; $userA-&gt;id,
            'subject' =&gt; 'Org A ticket',
        ]);

        Ticket::factory()-&gt;create([
            'organization_id' =&gt; $orgB-&gt;id,
            'user_id' =&gt; $userB-&gt;id,
            'subject' =&gt; 'Org B ticket',
        ]);

        $this-&gt;actingAs($userA);
        $this-&gt;assertEquals(1, Ticket::count());
        $this-&gt;assertEquals('Org A ticket', Ticket::first()-&gt;subject);

        $this-&gt;actingAs($userB);
        $this-&gt;assertEquals(1, Ticket::count());
        $this-&gt;assertEquals('Org B ticket', Ticket::first()-&gt;subject);
    }

    public function test_for_organization_scope_bypasses_global_scope(): void
    {
        $org = Organization::factory()-&gt;create();
        Category::factory()-&gt;create(['organization_id' =&gt; $org-&gt;id, 'name' =&gt; 'Support']);

        $this-&gt;actingAs(User::factory()-&gt;create());

        $results = Category::forOrganization($org-&gt;id)-&gt;get();
        $this-&gt;assertCount(1, $results);
        $this-&gt;assertEquals('Support', $results-&gt;first()-&gt;name);
    }
}
