        $this-&gt;actingAs(User::factory()-&gt;create());

        $results = Category::forOrganization($org-&gt;id)-&gt;get();
        $this-&gt;assertCount(1, $results);
        $this-&gt;assertEquals('Support', $results-&gt;first()-&gt;name);
    }
}
